<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>{{ $title ?? 'E-commerce Admin' }}</title><style>body{margin:0;background:#f4f7fb;color:#132b52;font-family:Inter,Arial,sans-serif}.shell{display:grid;grid-template-columns:245px 1fr;min-height:100vh}.side{background:#132b52;color:#fff;padding:26px 18px}.brand{font-size:20px;font-weight:800;margin:0 8px 32px}.brand small{display:block;color:#a9c6e8;font-size:11px;margin-top:5px}.side a{display:block;color:#dbeafe;text-decoration:none;padding:12px;border-radius:7px;margin:4px 0}.side a.active,.side a:hover{background:#28609a;color:#fff}.main{padding:30px;max-width:1280px;width:calc(100% - 60px)}.top{display:flex;justify-content:space-between;align-items:center;margin-bottom:26px}.card{background:#fff;border:1px solid #d8e2ee;border-radius:12px;padding:20px;box-shadow:0 4px 14px #132b5210}.grid{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:16px}.metric{font-size:30px;font-weight:800;margin-top:8px}.muted{color:#64748b;font-size:13px}table{width:100%;border-collapse:collapse}th,td{text-align:left;padding:12px;border-bottom:1px solid #e5edf5}th{font-size:12px;color:#64748b}button,.button{background:#1d4e89;border:0;border-radius:7px;color:#fff;padding:10px 14px;text-decoration:none;font-weight:700;cursor:pointer}.button.alt{background:#e7eff8;color:#132b52}input,textarea,select{width:100%;box-sizing:border-box;padding:10px;border:1px solid #bdcadb;border-radius:7px;margin-top:5px}label{display:block;font-size:13px;font-weight:700;margin-top:14px}.success{background:#dcfce7;color:#166534;padding:12px;border-radius:7px;margin-bottom:16px}.error{color:#b91c1c;font-size:13px}@media(max-width:800px){.shell{grid-template-columns:1fr}.side{display:flex;gap:5px;overflow:auto;padding:12px}.brand{display:none}.side a{white-space:nowrap}.main{width:auto;padding:18px}.grid{grid-template-columns:repeat(2,1fr)}}</style></head><body><div class="shell"><aside class="side"><div class="brand">NEXORA<small>E-commerce Administration</small></div><a class="{{ request()->routeIs('ecommerce.admin.dashboard')?'active':'' }}" href="{{ route('ecommerce.admin.dashboard') }}">Overview</a><a class="{{ request()->routeIs('ecommerce.admin.listings*')?'active':'' }}" href="{{ route('ecommerce.admin.listings') }}">Storefront Listings</a><a class="{{ request()->routeIs('ecommerce.admin.orders')?'active':'' }}" href="{{ route('ecommerce.admin.orders') }}">Storefront Orders</a><a href="{{ url('/manufacturing/boms') }}">Manufacturing BOMs</a><form method="post" action="{{ route('ecommerce.admin.logout') }}">@csrf<button style="background:transparent;color:#dbeafe;padding:12px;width:100%;text-align:left">Sign out</button></form></aside><main class="main"><div class="top"><div><h1 style="margin:0">{{ $heading ?? 'E-commerce Admin' }}</h1><p class="muted">{{ auth('ecommerce_admin')->user()?->getCompany()?->company_name }}</p></div><a class="button alt" href="{{ route('ecommerce.home', ['store' => auth('ecommerce_admin')->user()?->getCompany()?->ecommerce_slug]) }}" target="_blank">Open Storefront</a></div>@if(session('success'))<div class="success">{{ session('success') }}</div>@endif @yield('content')</main></div></body></html>
